'use strict';
const GAS_MODE = typeof google !== 'undefined' && !!google.script;
const SCRIPT_URL = '';

// ── GAS 통신 ──────────────────────────────────────────────
function callServer(action, payload={}) {
  return new Promise((resolve, reject) => {
    const waitMs = action === 'getImageDataUrl' ? 30000 : 45000;
    const timeout = setTimeout(() => reject(new Error('timeout')), waitMs);
    const _ok = d => { clearTimeout(timeout); resolve(d); };
    const _ng = e => { clearTimeout(timeout); reject(new Error(e.message||String(e))); };
    if (GAS_MODE) {
      const r = google.script.run.withSuccessHandler(_ok).withFailureHandler(_ng);
      switch(action){
        case 'loginOrRegister': r.loginOrRegister(payload.ban,payload.num,payload.name); break;
        case 'getPlayerInfo':   r.getPlayerInfo(payload.ban,payload.num,payload.name); break;
        case 'submitAnswer':    r.submitAnswer(payload.ban,payload.num,payload.name,payload.questionNum,payload.answer,payload.isCorrect); break;
        case 'saveStageScore':  r.saveStageScore(payload.ban,payload.num,payload.name,payload.stageName,payload.stageScore,payload.solved); break;
        case 'savePosition':    r.savePosition(payload.ban,payload.num,payload.name); break;
        case 'getQuizBank':     r.getQuizBank(payload.sheetName); break;
        case 'getImageDataUrl': r.getImageDataUrl(payload.fileId||payload.url); break;
        case 'getSheetNames':   r.getQuizSheetNames(); break;
        default: _ng(new Error('unknown action'));
      }
    } else {
      if (!SCRIPT_URL) { _ng(new Error('SCRIPT_URL 없음')); return; }
      fetch(SCRIPT_URL,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action,...payload})})
        .then(r=>r.json()).then(d=>{ if(d.ok===false) _ng(new Error(d.error)); else _ok(d); }).catch(_ng);
    }
  });
}

