// ── 픽셀 스프라이트 렌더러 ────────────────────────────────
function drawSprite(sprite, palette, cx, cy, ps, flipX) {
  const rows = sprite.length;
  const cols = sprite[0].length;
  const ox = cx - (cols * ps) / 2;
  const oy = cy - (rows * ps) / 2;
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const ci = sprite[r][flipX ? (cols-1-c) : c];
      if (!ci || !palette[ci]) continue;
      ctx.fillStyle = palette[ci];
      ctx.fillRect(ox + c*ps, oy + r*ps, ps, ps);
    }
  }
}

// 사전 렌더링용 offscreen cache
const spriteCache = new Map();
function getCachedSprite(key, sprite, palette, ps, flipX) {
  const cacheKey = key + (flipX?'_f':'') + '_' + ps;
  if (spriteCache.has(cacheKey)) return spriteCache.get(cacheKey);
  const rows = sprite.length, cols = sprite[0].length;
  const oc = document.createElement('canvas');
  oc.width = cols*ps; oc.height = rows*ps;
  const octx = oc.getContext('2d');
  for (let r=0; r<rows; r++) {
    for (let c=0; c<cols; c++) {
      const ci = sprite[r][flipX?(cols-1-c):c];
      if (!ci||!palette[ci]) continue;
      octx.fillStyle = palette[ci];
      octx.fillRect(c*ps, r*ps, ps, ps);
    }
  }
  spriteCache.set(cacheKey, oc);
  return oc;
}

